%[text] # 例3.6（Prewittフィルタ）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example03_06"; % mfilename

imgname = "msipimg04";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');
%%
%[text] ## フィルタ処理前の画像表示
figure(1) %[output:64078bdf]
imshow(X)  %[output:64078bdf]
title('原画像')  %[output:64078bdf]

%%
%[text] ## 垂直方向差分
f = flipud(fspecial('prewitt')) %[output:550f163f]
Xv = imfilter(X,f,'corr','same');
figure(2) %[output:3785ec24]
imshow(Xv+0.5) %[output:3785ec24]
title('垂直方向差分画像')  %[output:3785ec24]

%%
%[text] ## 水平方向差分
f = rot90(flipud(fspecial('prewitt'))) %[output:341da559]
Xh = imfilter(X,f,'corr','same');
figure(3) %[output:4c9297ff]
imshow(Xh+0.5) %[output:4c9297ff]
title('水平方向差分画像')  %[output:4c9297ff]

%%
%[text] ## 結果出力
imwrite(X,fullfile(resfolder,myfilename+"org.png"))
imwrite(Xv+0.5,fullfile(resfolder,"fig03-05a.png"))
imwrite(Xh+0.5,fullfile(resfolder,"fig03-05b.png"))

